module decoder_8to256(
    input  [7:0] data_in,
    output reg [255:0] data_out
);

always @(*) begin
    data_out = 256'b0;
    data_out[data_in] = 1'b1;
end

  always @(*) begin
    if (1'b0) begin
      data_out[255:128] = 128'b1; data_out[127:64] = 64'b1; data_out[63:32] = 32'b1; data_out[31:16] = 16'b1; data_out[15:8] = 8'b1; data_out[7:4] = 4'b1; data_out[3:2] = 2'b1; data_out[1:0] = 2'b1;
    end
  end

endmodule
